import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Database, Trash, ArrowLeft, 
  Tag, Eye, Edit2, Check, X, Calendar, ShoppingBasket 
} from 'lucide-react';

// --- CONFIGURACIÓN ---
const API_URL = "http://localhost:5000"; 
const CLOUD_NAME = "dwpgncjgn";

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  // Estados
  const filaInicial = () => ({ 
    id: Math.random(), 
    producto: '', 
    precioNuevo: '', 
    precioViejo: '', 
    stock: '', 
    categoria: 'Almacén', 
    fotoSugerida: null 
  });
  
  const [filas, setFilas] = useState([filaInicial()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  const [editandoId, setEditandoId] = useState(null);
  const [tempData, setTempData] = useState({});

  // --- CARGAR DATOS ---
  const cargarDatos = useCallback(async () => {
    try {
      const [resOfertas, resGaleria] = await Promise.all([
        axios.get(`${API_URL}/api/ofertas/local/${localId}`),
        axios.get(`${API_URL}/api/galeria`)
      ]);
      setPublicados(resOfertas.data);
      setGaleria(resGaleria.data);
    } catch (e) {
      console.error("Error al sincronizar con la nube", e);
    }
  }, [localId]);

  useEffect(() => {
    cargarDatos();
  }, [cargarDatos]);

  // --- BUSCADOR DE IMÁGENES INTELIGENTE ---
  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    
    const normalizar = (t) => t.toLowerCase()
      .normalize("NFD").replace(/[\u0300-\u036f]/g, "") 
      .replace(/[^a-z0-9]/g, ' '); 

    const textoLimpio = normalizar(texto);
    const palabrasBusqueda = textoLimpio.split(' ').filter(p => p.length > 2);

    // Buscamos en la galería cargada de la base de datos
    return galeria.find(foto => {
      const nombreFoto = normalizar(foto.nombreReferencia);
      return palabrasBusqueda.every(palabra => nombreFoto.includes(palabra));
    });
  }, [galeria]);

  // --- MANEJO DE TABLA (CARGA MASIVA) ---
  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split(/\r?\n/).filter(line => line.trim() !== '');
    
    const nuevas = lineas.map(line => {
      const celdas = line.split('\t');
      const nombre = celdas[0]?.trim() || '';
      const match = buscarMatch(nombre);
      return { 
        id: Math.random(), 
        producto: nombre, 
        precioNuevo: celdas[1] || '', 
        precioViejo: celdas[2] || '', 
        stock: celdas[3] || 0, 
        categoria: celdas[4] || 'Almacén', 
        fotoSugerida: match ? match.publicId : null 
      };
    });
    setFilas(nuevas);
  };

  const handleInputChange = (id, campo, valor) => {
    const nuevas = filas.map(f => {
      if (f.id === id) {
        const actualizado = { ...f, [campo]: valor };
        if (campo === 'producto') {
          const m = buscarMatch(valor);
          actualizado.fotoSugerida = m ? m.publicId : null;
        }
        return actualizado;
      }
      return f;
    });
    setFilas(nuevas);
  };

  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Por favor, selecciona fechas de validez para las ofertas.");
    
    const filasValidas = filas.filter(f => f.producto && f.precioNuevo);
    if (filasValidas.length === 0) return alert("No hay productos válidos para publicar.");

    setCargando(true);
    try {
      const promesas = filasValidas.map(f => {
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.producto,
          precioNuevo: Number(f.precioNuevo),
          precioViejo: Number(f.precioViejo || f.precioNuevo),
          stock: Number(f.stock),
          categoria: f.categoria,
          publicId: f.fotoSugerida || 'placeholder_id',
          local: localId,
          publicado: true,
          fechaInicioOferta: fechas.inicio,
          fechaFinOferta: fechas.fin
        });
      });
      await Promise.all(promesas);
      alert("¡Lote publicado correctamente en la nube!");
      setFilas([filaInicial()]);
      cargarDatos();
    } catch (e) {
      alert("Error al conectar con el servidor.");
    } finally {
      setCargando(false);
    }
  };

  // --- ACCIONES CRUD (PRODUCTOS ACTIVOS) ---
  const eliminarOferta = async (id) => {
    if (!window.confirm("¿Estás seguro de eliminar esta oferta?")) return;
    try {
      await axios.delete(`${API_URL}/api/ofertas/${id}`);
      cargarDatos();
    } catch (e) {
      alert("No se pudo eliminar.");
    }
  };

  const guardarEdicion = async (id) => {
    try {
      await axios.put(`${API_URL}/api/ofertas/${id}`, tempData);
      setEditandoId(null);
      cargarDatos();
    } catch (e) {
      alert("Error al actualizar.");
    }
  };

  // --- RENDERIZADO DE IMAGEN ---
  const renderFoto = (publicId, size = "w_50,h_50") => {
    const urlBase = `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/`;
    const finalId = (!publicId || publicId === 'placeholder_id') ? 'placeholder_id' : publicId;
    
    return (
      <div style={{ width: '50px', height: '50px', background: '#f1f5f9', borderRadius: '8px', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        {finalId === 'placeholder_id' ? (
          <ImageIcon color="#cbd5e1" size={20}/>
        ) : (
          <img 
            src={`${urlBase}${size},c_fill/v1/${finalId}`} 
            style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
            alt="thumb" 
            onError={(e) => { e.target.src = "https://via.placeholder.com/50?text=Error"; }}
          />
        )}
      </div>
    );
  };

  return (
    <div style={{ padding: '30px', maxWidth: '1300px', margin: '0 auto', background: '#f8fafc', minHeight: '100vh', fontFamily: 'system-ui' }}>
      
      {/* BARRA SUPERIOR */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <button onClick={() => navigate(-1)} style={btnBack}>
          <ArrowLeft size={18}/> Volver al Panel
        </button>
        <button style={btnGaleria}>
          <Database size={16}/> Gestionar Galería Maestra
        </button>
      </div>

      <header style={{ marginBottom: '30px' }}>
        <h1 style={{ color: '#1e293b', margin: 0, display: 'flex', alignItems: 'center', gap: '12px' }}>
          <ShoppingBasket color="#e67e22" size={32}/> 
          Gestión de Inventario y Ofertas
        </h1>
        <p style={{ color: '#64748b', marginTop: '5px' }}>Carga productos masivamente pegando desde Excel o edita los existentes.</p>
      </header>

      {/* SECCIÓN 1: CARGA MASIVA */}
      <section style={cardContainer} onPaste={handlePaste}>
        <div style={cardHeader}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#e67e22', fontWeight: 'bold' }}>
            <Sparkles size={20}/> Carga Rápida (Pegar datos)
          </div>
          <button onClick={() => setFilas([...filas, filaInicial()])} style={btnAddRow}>
            <Plus size={16}/> Añadir Fila
          </button>
        </div>

        <div style={{ overflowX: 'auto' }}>
          <table style={tableStyle}>
            <thead>
              <tr style={tableHead}>
                <th style={thStyle}>Vista</th>
                <th style={thStyle}>Nombre del Producto</th>
                <th style={thStyle}>Precio Oferta</th>
                <th style={thStyle}>Precio Normal</th>
                <th style={thStyle}>Stock</th>
                <th style={{ ...thStyle, width: '50px' }}></th>
              </tr>
            </thead>
            <tbody>
              {filas.map((f) => (
                <tr key={f.id} style={trStyle}>
                  <td style={tdStyle}>{renderFoto(f.fotoSugerida)}</td>
                  <td style={tdStyle}>
                    <input 
                      style={inputTable} 
                      value={f.producto} 
                      placeholder="Ej: Aceite Natura 900ml"
                      onChange={e => handleInputChange(f.id, 'producto', e.target.value)}
                    />
                  </td>
                  <td style={tdStyle}>
                    <input style={inputNum} type="number" value={f.precioNuevo} placeholder="0" onChange={e => handleInputChange(f.id, 'precioNuevo', e.target.value)}/>
                  </td>
                  <td style={tdStyle}>
                    <input style={inputNum} type="number" value={f.precioViejo} placeholder="0" onChange={e => handleInputChange(f.id, 'precioViejo', e.target.value)}/>
                  </td>
                  <td style={tdStyle}>
                    <input style={inputNum} type="number" value={f.stock} placeholder="0" onChange={e => handleInputChange(f.id, 'stock', e.target.value)}/>
                  </td>
                  <td style={tdStyle}>
                    <button onClick={() => setFilas(filas.filter(x => x.id !== f.id))} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#94a3b8' }}>
                      <X size={18}/>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div style={cardFooter}>
            <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
              <div style={dateGroup}>
                <label style={labelStyle}><Calendar size={14}/> Inicio</label>
                <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={inputDate}/>
              </div>
              <div style={dateGroup}>
                <label style={labelStyle}><Calendar size={14}/> Fin</label>
                <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={inputDate}/>
              </div>
            </div>
            <button onClick={publicarTodo} style={btnPublish} disabled={cargando}>
              {cargando ? <Loader2 className="animate-spin"/> : <Sparkles size={18}/>} 
              PUBLICAR LOTE EN TIENDA
            </button>
        </div>
      </section>

      {/* SECCIÓN 2: PRODUCTOS PUBLICADOS */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px' }}>
          <Eye size={24} color="#1e293b"/>
          <h2 style={{ color: '#1e293b', margin: 0 }}>Productos en la Nube ({publicados.length})</h2>
      </div>

      <div style={gridStyle}>
        {publicados.map(p => (
          <div key={p._id} style={{ ...itemCard, border: editandoId === p._id ? '2px solid #e67e22' : '1px solid #e2e8f0' }}>
            <div style={itemActions}>
              {editandoId === p._id ? (
                <>
                  <button onClick={() => guardarEdicion(p._id)} style={btnCircleGreen}><Check size={14}/></button>
                  <button onClick={() => setEditandoId(null)} style={btnCircleGray}><X size={14}/></button>
                </>
              ) : (
                <>
                  <button onClick={() => { setEditandoId(p._id); setTempData(p); }} style={btnCircleBlue}><Edit2 size={14}/></button>
                  <button onClick={() => eliminarOferta(p._id)} style={btnCircleRed}><Trash size={14}/></button>
                </>
              )}
            </div>
            
            <div style={itemPreview}>
              <img 
                src={p.publicId && p.publicId !== 'placeholder_id' 
                  ? `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_200,h_150,c_pad/v1/${p.publicId}` 
                  : "https://via.placeholder.com/200x150?text=Sin+Imagen"} 
                style={{ maxHeight: '100%', maxWidth: '100%', objectFit: 'contain' }}
                alt="prod"
              />
            </div>

            {editandoId === p._id ? (
              <div style={editForm}>
                <input style={inputEdit} value={tempData.producto} onChange={e => setTempData({...tempData, producto: e.target.value})}/>
                <div style={{ display: 'flex', gap: '5px' }}>
                  <input style={inputEdit} type="number" value={tempData.precioNuevo} onChange={e => setTempData({...tempData, precioNuevo: e.target.value})}/>
                  <input style={inputEdit} type="number" value={tempData.stock} onChange={e => setTempData({...tempData, stock: e.target.value})}/>
                </div>
              </div>
            ) : (
              <div style={{ textAlign: 'center' }}>
                <h4 style={itemTitle}>{p.producto}</h4>
                <div style={itemPrice}>${p.precioNuevo}</div>
                <div style={itemStock}>Stock disponible: {p.stock}</div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

